/**
 * ace-overlay
 * Overlay Ace Editor on normal input/textarea elements.
 *
 * Requires the global `ace` object (Ace Editor) to be loaded separately.
 */

/// <reference types="ace" />

// ---------------------------------------------------------------------------
// Option types
// ---------------------------------------------------------------------------

export interface OverlayCallbackArg {
    /** The Ace Editor instance that was created or is about to be destroyed. */
    editor: ace.Ace.Editor;
}

export interface OverlayOptions {
    /**
     * The base element used as the positioning reference for the overlay div.
     * The overlay is appended to this element.
     * @default document.body
     */
    base?: Element;

    /**
     * Called immediately after the Ace Editor is created and focused.
     * Use this to configure the editor (e.g. set syntax mode, theme, etc.).
     */
    oncreate?: (arg: OverlayCallbackArg) => void;

    /**
     * Called just before the Ace Editor is destroyed (on blur).
     * Use this to read the final value or perform cleanup.
     */
    ondestroy?: (arg: OverlayCallbackArg) => void;
}

export interface ActivateOptions extends OverlayOptions {
    /**
     * When `true`, polls every 100ms and applies overlays to dynamically
     * added `input` / `textarea` elements inside the container.
     * The returned timer ID can be used to stop polling via `clearInterval`.
     */
    dynamic?: boolean;
}

// ---------------------------------------------------------------------------
// Return types
// ---------------------------------------------------------------------------

export interface Rect {
    left: number;
    top: number;
    width: number;
    height: number;
}

// ---------------------------------------------------------------------------
// Symbols
// ---------------------------------------------------------------------------

/**
 * Symbol used as a property key on an element to indicate that
 * `activate1` has already attached a click listener to it.
 * Prevents duplicate listeners from being registered.
 *
 * @example
 * if (element[acted]) { ... } // already activated
 */
export declare const acted: unique symbol;

/**
 * Symbol used as a property key on an element to store the currently
 * active Ace Editor instance overlaying that element.
 *
 * @example
 * const editor = element[sym_editor]; // get the live editor, if any
 */
export declare const sym_editor: unique symbol;

// ---------------------------------------------------------------------------
// Functions
// ---------------------------------------------------------------------------

/**
 * Returns the position and size of `element` relative to `base`.
 *
 * @param element - The target element.
 * @param base    - The reference ancestor element. Defaults to `document.body`.
 * @returns An object with `left`, `top`, `width`, `height` in pixels.
 *
 * @example
 * const { left, top, width, height } = rect(input, document.body);
 */
export declare function rect(element: Element, base?: Element): Rect;

/**
 * Attaches a click listener to a single `input` or `textarea` element
 * that launches an Ace Editor overlay on click.
 *
 * Does nothing if the element has already been activated (checked via
 * the `acted` symbol).
 *
 * @param base    - The base/container element (used as positioning reference).
 * @param element - The `input` or `textarea` to activate.
 * @param opt     - Overlay options (excluding `dynamic`).
 */
export declare function activate1(
    base: Element,
    element: HTMLInputElement | HTMLTextAreaElement,
    opt?: OverlayOptions
): void;

/**
 * Attaches click-to-overlay behavior to all `input` and `textarea`
 * elements found inside `container`.
 *
 * When `opt.dynamic` is `true`, a 100ms interval is started to also
 * handle elements added to the DOM after the initial call.
 *
 * @param container - The container element to search within.
 * @param opt       - Options including an optional `dynamic` flag.
 * @returns When `dynamic` is `true`, the interval ID (pass to `clearInterval`
 *          to stop). Otherwise `undefined`.
 *
 * @example
 * // Static: applies to elements already in the DOM
 * activate(document.querySelector("#form"), { base: document.body });
 *
 * @example
 * // Dynamic: also applies to elements added later
 * const timerId = activate(container, { dynamic: true });
 * // later...
 * clearInterval(timerId);
 */
export declare function activate(
    container: Element,
    opt: ActivateOptions
): ReturnType<typeof setInterval> | undefined;

/**
 * Immediately overlays an Ace Editor on top of the given `input` or
 * `textarea` element, adopting its position, size, and font size.
 *
 * **Lifecycle:**
 * 1. A `<div>` is created at the same position as the element and
 *    appended to `opt.base` (default: `document.body`).
 * 2. An Ace Editor is initialised inside that `<div>`.
 * 3. The editor's content is initialised from `element.value`.
 * 4. While the editor is open, every keystroke syncs back to `element.value`
 *    and dispatches an `"input"` event on the element.
 * 5. On `blur`, a `"change"` event is dispatched, `opt.ondestroy` is called,
 *    the editor is destroyed, and the overlay `<div>` is removed from the DOM.
 *
 * For `<input>` elements, a single-line editor is used (newlines are suppressed).
 *
 * The active editor instance is also stored on the element under the
 * `sym_editor` symbol and removed when the editor is destroyed.
 *
 * @param element - The `input` or `textarea` to overlay.
 * @param opt     - Overlay options.
 * @returns The Ace Editor instance.
 *
 * @example
 * import { overlay } from "ace-overlay";
 *
 * const editor = overlay(document.querySelector("textarea"), {
 *     base: document.body,
 *     oncreate({ editor }) {
 *         editor.session.setMode("ace/mode/javascript");
 *     },
 *     ondestroy({ editor }) {
 *         console.log("final value:", editor.session.getValue());
 *     },
 * });
 */
export declare function overlay(
    element: HTMLInputElement | HTMLTextAreaElement,
    opt?: OverlayOptions
): ace.Ace.Editor;
